import React, { useState } from 'react'
import { css } from '@linaria/core'
import { appName } from '@fs/zion-config'
import FuzzySearch from 'fuzzy-search'
import { resetExperiments } from './core'
import { useExperimentsList } from './hooks'
import ExperimentList from './ExperimentList'

const dialogCss = css`
  z-index: 10; // above everything else in the app because this is only for debugging purposes and not users
  border: none;
  border-radius: 8px;
  box-shadow:
    0 8px 32px rgba(0, 0, 0, 0.12),
    0 2px 8px rgba(0, 0, 0, 0.08);
  padding: 0;
  max-width: 600px;
  width: 90vw;
  height: auto;
  max-height: 80vh;
  min-height: min(400px, 60vh);
  overflow: hidden;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
  display: flex;
  flex-direction: column;

  /* Center the dialog on the page */
  position: fixed;
  top: 50%;
  inset-inline-start: 50%;
  transform: translate(-50%, -50%);
  margin: 0;

  &::backdrop {
    background: rgba(0, 0, 0, 0.65);
    backdrop-filter: blur(4px);
  }

  /* Tablet and below */
  @media (max-width: 768px) {
    width: 95vw;
    max-height: 85vh;
    border-radius: 12px;
  }

  /* Mobile devices */
  @media (max-width: 640px) {
    width: 100vw;
    height: 100vh;
    max-height: 100vh;
    min-height: 100vh;
    border-radius: 0;
    top: 0;
    inset-inline-start: 0;
    transform: none;
  }
`

const formCss = css`
  display: flex;
  flex-direction: column;
  flex: 1;
  min-height: 0;
  overflow: hidden;
`

const headerCss = css`
  padding: 20px 24px;
  border-bottom: 1px solid #e5e7eb;
  background: #f9fafb;
  flex-shrink: 0;

  h2 {
    margin: 0;
    font-size: 20px;
    font-weight: 600;
    color: #111827;
  }

  @media (max-width: 640px) {
    padding: 16px 20px;

    h2 {
      font-size: 18px;
    }
  }
`

const filterSectionCss = css`
  padding: 16px 24px;
  border-bottom: 1px solid #e5e7eb;
  background: #ffffff;
  flex-shrink: 0;

  label {
    display: block;
    font-size: 14px;
    font-weight: 500;
    color: #374151;
    margin-bottom: 6px;
  }

  input[type='text'] {
    width: 100%;
    padding: 8px 12px;
    border: 1px solid #d1d5db;
    border-radius: 6px;
    font-size: 14px;
    transition:
      border-color 0.15s,
      box-shadow 0.15s;
    box-sizing: border-box;

    &:focus {
      outline: none;
      border-color: #8b5cf6;
      box-shadow: 0 0 0 3px rgba(139, 92, 246, 0.1);
    }
  }

  @media (max-width: 640px) {
    padding: 12px 20px;

    input[type='text'] {
      font-size: 16px; /* Prevents zoom on iOS */
    }
  }
`

const contentCss = css`
  flex: 1;
  overflow-y: auto;
  padding: 24px;
  min-height: 0;
  -webkit-overflow-scrolling: touch; /* Smooth scrolling on iOS */

  h3 {
    margin: 0 0 16px 0;
    font-size: 16px;
    font-weight: 600;
    color: #111827;
  }

  h3:not(:first-child) {
    margin-top: 32px;
  }

  @media (max-width: 640px) {
    padding: 20px;

    h3 {
      font-size: 15px;
    }

    h3:not(:first-child) {
      margin-top: 24px;
    }
  }
`

const footerCss = css`
  padding: 16px 24px;
  border-top: 1px solid #e5e7eb;
  background: #f9fafb;
  display: flex;
  gap: 12px;
  justify-content: flex-end;
  flex-shrink: 0;

  button {
    padding: 8px 16px;
    border: 1px solid #d1d5db;
    border-radius: 6px;
    font-size: 14px;
    font-weight: 500;
    cursor: pointer;
    transition: all 0.15s;
    background: #ffffff;
    color: #374151;

    &:hover {
      background: #f3f4f6;
      border-color: #9ca3af;
    }

    &:focus {
      outline: none;
      box-shadow: 0 0 0 3px rgba(139, 92, 246, 0.1);
    }

    &[data-emphasis='high'] {
      background: #8b5cf6;
      color: #ffffff;
      border-color: #8b5cf6;

      &:hover {
        background: #7c3aed;
        border-color: #7c3aed;
      }
    }

    &[data-emphasis='medium'] {
      background: #f3f4f6;
      color: #374151;

      &:hover {
        background: #e5e7eb;
      }
    }
  }

  @media (max-width: 640px) {
    padding: 12px 20px;
    flex-direction: column-reverse;
    gap: 8px;

    button {
      width: 100%;
      padding: 12px 16px;
    }
  }

  @media (max-width: 480px) {
    /* Extra small screens - even tighter spacing */
    padding: 12px 16px;
  }
`

const hasWindow = typeof window !== 'undefined'

// appName === 'undefined' in some environments like Storybook PR Previews
const localName = !appName || appName === 'undefined' ? 'App Level' : appName

export default function Experiments({ initiallyOpen, isOpen, setIsOpen }) {
  const [sharedExps, toggleSharedExperiment] = useExperimentsList('shared')
  const [localExps, toggleLocalExperiment] = useExperimentsList('local')

  const [filter, setFilter] = useState('')

  const localSearcher = new FuzzySearch(localExps, ['name'])
  const sharedSearcher = new FuzzySearch(sharedExps, ['name'])

  const localResults = localSearcher.search(filter)
  const sharedResults = sharedSearcher.search(filter)

  return (
    <dialog open={isOpen || initiallyOpen} className={dialogCss} aria-labelledby="experiments-title">
      <form method="dialog" className={formCss}>
        <header className={headerCss}>
          <h2 id="experiments-title">Experiments</h2>
        </header>

        <div className={filterSectionCss}>
          <label>
            Filter <input type="text" onChange={(e) => setFilter(e.target.value)} value={filter} />
          </label>
        </div>

        <div className={contentCss}>
          <h3>{localName.toUpperCase()}</h3>
          <ExperimentList list={localResults} onToggle={toggleLocalExperiment} />

          <h3>SHARED</h3>
          <ExperimentList list={sharedResults} onToggle={toggleSharedExperiment} />
        </div>

        <footer className={footerCss}>
          <button type="button" onClick={() => setIsOpen(false)} data-emphasis="medium">
            Cancel
          </button>
          <button type="button" onClick={() => resetExperiments()} data-emphasis="medium">
            🔄 Reset Experiments
          </button>
          <button type="button" onClick={() => hasWindow && window.location.reload()} data-emphasis="high">
            Apply
          </button>
        </footer>
      </form>
    </dialog>
  )
}
