import React from 'react'
import PropTypes from 'prop-types'
import { css } from '@linaria/core'

const listCss = css`
  list-style: none;
  padding: 0;
  margin: 0;
`

const listItemCss = css`
  margin-bottom: 8px;

  &:last-child {
    margin-bottom: 0;
  }

  label {
    display: flex;
    align-items: center;
    padding: 10px 12px;
    border-radius: 6px;
    cursor: pointer;
    transition: background-color 0.15s;
    font-size: 14px;
    color: #374151;
    user-select: none;

    &:hover {
      background-color: #f3f4f6;
    }
  }

  input[type='checkbox'] {
    margin: 0;
    margin-inline-end: 12px;
    width: 18px;
    height: 18px;
    cursor: pointer;
    accent-color: #8b5cf6;
    flex-shrink: 0;
  }

  @media (max-width: 640px) {
    margin-bottom: 4px;

    label {
      padding: 12px 10px;
      font-size: 15px;
      min-height: 44px; /* Minimum touch target size for accessibility */
    }

    input[type='checkbox'] {
      width: 20px;
      height: 20px;
      margin-inline-end: 14px;
    }
  }
`

const emptyStateCss = css`
  padding: 20px;
  text-align: center;
  color: #9ca3af;
  font-size: 14px;
  font-style: italic;

  @media (max-width: 640px) {
    padding: 24px 16px;
    font-size: 15px;
  }
`

export default function ExperimentList({ list, onToggle }) {
  return (
    <ul className={listCss}>
      {list && list.length ? (
        list.map(({ name, value }) => (
          <li key={name} className={listItemCss}>
            <label>
              <input type="checkbox" name={name} checked={value} onChange={() => onToggle(name, !value)} />
              {name}
            </label>
          </li>
        ))
      ) : (
        <li className={emptyStateCss}>No Experiments</li>
      )}
    </ul>
  )
}

ExperimentList.propTypes = {
  list: PropTypes.arrayOf(PropTypes.shape({ name: PropTypes.string.isRequired, value: PropTypes.bool.isRequired })),
  onToggle: PropTypes.func,
}
